//! The canonical index: compose the two scanners into `specmap.json`
//! (PROP-014 §2.5) — derived, deterministic, committed, regenerated by
//! `cargo xtask specmap`, gated by `--check` exactly the way
//! `check-codegen` gates the wire types.

use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use vibe_wire::generated::specmap::Specmap;

use crate::{mdspec, rscan};

/// Repo-relative location of the committed index.
pub const INDEX_REL_PATH: &str = "specmap.json";

/// Current index schema number.
pub const SCHEMA: u32 = 1;

/// Build the index for the tree under `root`. Pure function of the
/// tree: same tree → same value.
pub fn build(root: &Path) -> Specmap {
    let (mut spec_units, mut md_warnings) = mdspec::scan_spec_tree(root);
    let (mut code_items, mut edges, mut rs_warnings) = rscan::scan_workspace(root);

    let mut warnings = Vec::new();
    warnings.append(&mut md_warnings);
    warnings.append(&mut rs_warnings);

    // Canonical ordering — the determinism contract.
    spec_units.sort_by(|a, b| (&a.docPath, a.line).cmp(&(&b.docPath, b.line)));
    code_items.sort_by(|a, b| (&a.symbol, &a.file, a.line).cmp(&(&b.symbol, &b.file, b.line)));
    code_items.dedup_by(|a, b| a.symbol == b.symbol && a.file == b.file && a.line == b.line);
    edges.sort_by(|a, b| {
        (&a.fromSymbol, verb_key(a), &a.uri, &a.file, a.line).cmp(&(
            &b.fromSymbol,
            verb_key(b),
            &b.uri,
            &b.file,
            b.line,
        ))
    });
    warnings.sort_by(|a, b| {
        (&a.file, a.line, &a.code, &a.message).cmp(&(&b.file, b.line, &b.code, &b.message))
    });

    Specmap {
        schema: SCHEMA,
        specUnits: spec_units,
        codeItems: code_items,
        edges,
        warnings,
    }
}

fn verb_key(e: &vibe_wire::generated::specmap::Edge) -> u8 {
    use vibe_wire::generated::specmap::EdgeVerb::*;
    match e.verb {
        Implements => 0,
        Verifies => 1,
        Documents => 2,
        Deviates => 3,
        Informs => 4,
    }
}

/// Canonical bytes: pretty JSON + trailing newline.
pub fn to_canonical_bytes(map: &Specmap) -> Result<String> {
    let mut s = serde_json::to_string_pretty(map).context("serialising specmap")?;
    s.push('\n');
    Ok(s)
}

pub fn index_path(root: &Path) -> PathBuf {
    root.join(INDEX_REL_PATH)
}

/// Regenerate and write `specmap.json`. Returns (path, summary).
pub fn write(root: &Path) -> Result<(PathBuf, Summary)> {
    let map = build(root);
    let summary = Summary::of(&map);
    let bytes = to_canonical_bytes(&map)?;
    let path = index_path(root);
    std::fs::write(&path, bytes).with_context(|| format!("writing {}", path.display()))?;
    Ok((path, summary))
}

/// `--check`: regenerate and byte-compare against the committed file.
pub fn check(root: &Path) -> Result<std::result::Result<Summary, String>> {
    let map = build(root);
    let summary = Summary::of(&map);
    let fresh = to_canonical_bytes(&map)?;
    let path = index_path(root);
    let committed = std::fs::read_to_string(&path).with_context(|| {
        format!(
            "reading {} — run `cargo xtask specmap` first",
            path.display()
        )
    })?;
    if fresh == committed {
        Ok(Ok(summary))
    } else {
        Ok(Err(format!(
            "`{}` is out of date relative to the tree. \
             Run `cargo xtask specmap` and commit the result.",
            path.display()
        )))
    }
}

/// Counts for the human one-liner.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Summary {
    pub spec_units: usize,
    pub code_items: usize,
    pub edges: usize,
    pub warnings: usize,
}

impl Summary {
    pub fn of(map: &Specmap) -> Self {
        Summary {
            spec_units: map.specUnits.len(),
            code_items: map.codeItems.len(),
            edges: map.edges.len(),
            warnings: map.warnings.len(),
        }
    }
}

impl std::fmt::Display for Summary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "{} spec units, {} tagged code items, {} edges, {} warnings",
            self.spec_units, self.code_items, self.edges, self.warnings
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn repo_root() -> PathBuf {
        Path::new(env!("CARGO_MANIFEST_DIR"))
            .parent()
            .unwrap()
            .parent()
            .unwrap()
            .to_path_buf()
    }

    /// PROP-014 §2.5: determinism is a tested property — index twice,
    /// assert byte-identical. Runs over the real repository tree.
    #[test]
    fn index_is_deterministic_over_the_real_tree() {
        let root = repo_root();
        let a = to_canonical_bytes(&build(&root)).unwrap();
        let b = to_canonical_bytes(&build(&root)).unwrap();
        assert_eq!(a, b);
        assert!(a.ends_with('\n'));
    }

    #[test]
    fn real_tree_has_a_node_inventory() {
        let root = repo_root();
        let map = build(&root);
        // The spec corpus is large; the index must inventory it even
        // with zero edges (Phase 0 acceptance: full node inventory).
        assert!(
            map.specUnits.len() > 100,
            "expected a substantial unit inventory, got {}",
            map.specUnits.len()
        );
        // Ordering invariant: (doc_path, line) non-decreasing.
        assert!(
            map.specUnits
                .windows(2)
                .all(|w| (&w[0].docPath, w[0].line) <= (&w[1].docPath, w[1].line))
        );
    }
}
